const express = require('express');
const bodyParser = require('body-parser');
const { exec } = require('child_process');
const axios = require('axios');
const app = express();
const PORT = process.env.PORT || 3000;

app.use(bodyParser.json());

const AI_MODEL_URL = 'https://api.your-llm-provider.com/generate'; // Replace with your LLM API URL
const API_KEY = 'your_api_key'; // Replace with your API key

async function generateCode(prompt) {
    try {
        const response = await axios.post(AI_MODEL_URL, {
            prompt: prompt,
            max_tokens: 150,
        }, {
            headers: {
                'Authorization': `Bearer ${API_KEY}`,
                'Content-Type': 'application/json'
            }
        });
        return response.data.code;
    } catch (error) {
        console.error('Error generating code:', error);
        throw new Error('Code generation failed');
    }
}

app.post('/generate', async (req, res) => {
    const { description } = req.body;

    if (!description) {
        return res.status(400).send('Description is required');
    }

    const prompt = `Generate secure JavaScript code for the following task: ${description}`;
    
    try {
        const code = await generateCode(prompt);
        exec(code, (error, stdout, stderr) => {
            if (error) {
                console.error(`Execution error: ${error}`);
                return res.status(500).send('Code execution failed');
            }
            res.json({ output: stdout, error: stderr });
        });
    } catch (error) {
        res.status(500).send(error.message);
    }
});

app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});